3	namespace App\Http\Controllers;
4	
5	use App\Http\Requests\LearnerRequest;
6	use App\Http\Resources\LearnerResource;
7	use App\Models\Learner;
8	use Illuminate\Http\JsonResponse;
9	use Illuminate\Http\Request;
10	use Illuminate\Http\Resources\Json\AnonymousResourceCollection;
11	
12	class LearnerController extends Controller
13	{
14	    public function index(Request $request): AnonymousResourceCollection
15	    {
16	        $query = Learner::with('identifiers');
17	
18	        if ($request->has('status')) {
19	            $query->where('status', $request->status);
20	        }
21	
22	        if ($request->has('search')) {
23	            $search = $request->search;
24	            $query->where(function ($q) use ($search) {
25	                $q->where('first_name', 'like', "%{$search}%")
26	                    ->orWhere('last_name', 'like', "%{$search}%")
27	                    ->orWhere('search_email', 'like', "%{$search}%")
28	                    ->orWhere('search_phone', 'like', "%{$search}%");
29	            });
30	        }
31	
32	        if ($request->has('nationality')) {
33	            $query->where('nationality', $request->nationality);
34	        }
35	
36	        if ($request->has('is_minor') && $request->is_minor === 'true') {
37	            $query->whereNotNull('date_of_birth')
38	                ->whereDate('date_of_birth', '>', now()->subYears(18));
39	        }
40	
41	        $sortField = $request->get('sort', 'created_at');
42	        $sortDir = $request->get('direction', 'desc');
43	        $allowedSorts = ['first_name', 'last_name', 'email', 'created_at', 'updated_at', 'date_of_birth'];
44	
45	        if (in_array($sortField, $allowedSorts)) {
46	            $query->orderBy($sortField, $sortDir === 'asc' ? 'asc' : 'desc');
47	        }
48	
49	        $perPage = min((int) $request->get('per_page', 25), 100);
50	
51	        return LearnerResource::collection($query->paginate($perPage));
52	    }
53	
54	    public function store(LearnerRequest $request): JsonResponse
55	    {
56	        $learner = Learner::create($request->validated());
57	        $learner->load('identifiers');
58	
59	        return response()->json([
60	            'message' => 'Learner created successfully.',
61	            'data' => new LearnerResource($learner),
62	        ], 201);
63	    }
64	
65	    public function show(int $id): JsonResponse
66	    {
67	        $learner = Learner::with('identifiers')->findOrFail($id);
68	
69	        return response()->json([
70	            'data' => new LearnerResource($learner),
71	        ]);
72	    }
73	
74	    public function update(LearnerRequest $request, int $id): JsonResponse
75	    {
76	        $learner = Learner::findOrFail($id);
77	        $learner->update($request->validated());
78	        $learner->load('identifiers');
79	
80	        return response()->json([
81	            'message' => 'Learner updated successfully.',
82	            'data' => new LearnerResource($learner),
83	        ]);
84	    }
85	
86	    public function destroy(int $id): JsonResponse
87	    {
88	        $learner = Learner::findOrFail($id);
89	        $learner->delete();
90	
91	        return response()->json([
92	            'message' => 'Learner deleted successfully.',
93	        ]);
94	    }
95	}
