3	namespace App\Http\Controllers;
4	
5	use App\Jobs\ProcessEnrollmentApproval;
6	use App\Models\Approval;
7	use App\Models\Enrollment;
8	use App\Services\EnrollmentWorkflowService;
9	use Illuminate\Http\JsonResponse;
10	use Illuminate\Http\Request;
11	
12	class ApprovalController extends Controller
13	{
14	    private EnrollmentWorkflowService $workflowService;
15	
16	    public function __construct(EnrollmentWorkflowService $workflowService)
17	    {
18	        $this->workflowService = $workflowService;
19	    }
20	
21	    /**
22	     * List approvals, optionally filtered by enrollment or status.
23	     */
24	    public function index(Request $request): JsonResponse
25	    {
26	        $query = Approval::with(['enrollment.learner', 'reviewer']);
27	
28	        if ($request->has('enrollment_id')) {
29	            $query->where('enrollment_id', $request->enrollment_id);
30	        }
31	
32	        if ($request->has('status')) {
33	            $query->where('status', $request->status);
34	        }
35	
36	        if ($request->has('reviewer_id')) {
37	            $query->where('reviewer_id', $request->reviewer_id);
38	        }
39	
40	        // Show pending approvals for the current reviewer by default
41	        if ($request->has('my_queue') && $request->my_queue === 'true') {
42	            $query->where(function ($q) use ($request) {
43	                $q->where('reviewer_id', $request->user()->id)
44	                    ->orWhereNull('reviewer_id');
45	            })->whereIn('status', ['pending', 'in_review']);
46	        }
47	
48	        $perPage = min((int) $request->get('per_page', 25), 100);
49	
50	        return response()->json(
51	            $query->orderBy('created_at', 'desc')->paginate($perPage)
52	        );
53	    }
54	
55	    /**
56	     * Show a single approval with enrollment details.
57	     */
58	    public function show(int $id): JsonResponse
59	    {
60	        $approval = Approval::with(['enrollment.learner', 'reviewer'])->findOrFail($id);
61	
62	        return response()->json(['data' => $approval]);
63	    }
64	
65	    /**
66	     * Submit an approval decision (approve or reject).
67	     * Dispatches processing to the queue.
68	     */
69	    public function decide(Request $request, int $id): JsonResponse
70	    {
71	        $request->validate([
72	            'decision' => 'required|string|in:approved,rejected',
73	            'comments' => 'nullable|string|max:2000',
74	            'reason_code' => 'nullable|string|max:100',
75	        ]);
76	
77	        $approval = Approval::with('enrollment')->findOrFail($id);
78	        $enrollment = $approval->enrollment;
79	
80	        if (!$approval->isPending()) {
81	            return response()->json([
82	                'error' => 'Invalid State',
83	                'message' => 'This approval has already been decided.',
84	            ], 422);
85	        }
86	
87	        if ($enrollment->status !== Enrollment::STATUS_UNDER_REVIEW) {
88	            return response()->json([
89	                'error' => 'Invalid State',
90	                'message' => 'The enrollment is not currently in review.',
91	            ], 422);
92	        }
93	
94	        // Dispatch to queue for processing
95	        ProcessEnrollmentApproval::dispatch(
96	            $enrollment->id,
97	            $request->user()->id,
98	            $request->decision,
99	            $request->comments,
100	            $request->reason_code
101	        );
102	
103	        return response()->json([
104	            'message' => 'Approval decision queued for processing.',
105	            'approval_id' => $approval->id,
106	            'enrollment_id' => $enrollment->id,
107	            'decision' => $request->decision,
108	        ], 202);
109	    }
110	
111	    /**
112	     * Directly process an approval decision (synchronous).
113	     */
114	    public function decideSync(Request $request, int $id): JsonResponse
115	    {
116	        $request->validate([
117	            'decision' => 'required|string|in:approved,rejected',
118	            'comments' => 'nullable|string|max:2000',
119	            'reason_code' => 'nullable|string|max:100',
120	        ]);
121	
122	        $approval = Approval::with('enrollment')->findOrFail($id);
123	        $enrollment = $approval->enrollment;
124	
125	        if (!$approval->isPending()) {
126	            return response()->json([
127	                'error' => 'Invalid State',
128	                'message' => 'This approval has already been decided.',
129	            ], 422);
130	        }
131	
132	        if ($enrollment->status !== Enrollment::STATUS_UNDER_REVIEW) {
133	            return response()->json([
134	                'error' => 'Invalid State',
135	                'message' => 'The enrollment is not currently in review.',
136	            ], 422);
137	        }
138	
139	        try {
140	            $enrollment = $this->workflowService->processApproval(
141	                $enrollment,
142	                $request->user(),
143	                $request->decision,
144	                $request->comments,
145	                $request->reason_code
146	            );
147	        } catch (\InvalidArgumentException $e) {
148	            return response()->json([
149	                'error' => 'Processing Error',
150	                'message' => $e->getMessage(),
151	            ], 422);
152	        }
153	
154	        $enrollment->load(['learner', 'approvals', 'lastActor']);
155	
156	        return response()->json([
157	            'message' => "Approval decision '{$request->decision}' processed.",
158	            'data' => $enrollment,
159	            'workflow' => $this->workflowService->getWorkflowStatus($enrollment),
160	        ]);
161	    }
162	
163	    /**
164	     * Claim a pending approval for review (assign to current user).
165	     */
166	    public function claim(Request $request, int $id): JsonResponse
167	    {
168	        $approval = Approval::findOrFail($id);
169	
170	        if (!$approval->isPending()) {
171	            return response()->json([
172	                'error' => 'Invalid State',
173	                'message' => 'This approval cannot be claimed.',
174	            ], 422);
175	        }
176	
177	        $approval->update([
178	            'reviewer_id' => $request->user()->id,
179	            'status' => 'in_review',
180	        ]);
181	
182	        $approval->load(['enrollment.learner', 'reviewer']);
183	
184	        return response()->json([
185	            'message' => 'Approval claimed for review.',
186	            'data' => $approval,
187	        ]);
188	    }
189	}
