14	    public function __construct(LocationService $locationService)
15	    {
16	        $this->locationService = $locationService;
17	    }
18	
19	    public function index(Request $request): JsonResponse
20	    {
21	        $query = Location::query();
22	
23	        if ($request->has('type')) {
24	            $query->where('type', $request->type);
25	        }
26	
27	        if ($request->has('is_active')) {
28	            $query->where('is_active', $request->is_active === 'true');
29	        }
30	
31	        if ($request->has('search')) {
32	            $search = $request->search;
33	            $query->where(function ($q) use ($search) {
34	                $q->where('name', 'like', "%{$search}%")
35	                    ->orWhere('address', 'like', "%{$search}%")
36	                    ->orWhere('display_address', 'like', "%{$search}%");
37	            });
38	        }
39	
40	        $perPage = min((int) $request->get('per_page', 25), 100);
41	        $locations = $query->paginate($perPage);
42	
43	        $canViewPrecise = $this->canViewPreciseCoordinates($request);
44	
45	        $locations->getCollection()->transform(function (Location $location) use ($canViewPrecise) {
46	            return $canViewPrecise
47	                ? $this->locationService->formatForAuthorized($location)
48	                : $this->locationService->formatForUnauthorized($location);
49	        });
50	
51	        return response()->json($locations);
52	    }
53	
54	    public function store(Request $request): JsonResponse
55	    {
56	        $request->validate([
57	            'name' => 'required|string|max:255',
58	            'type' => 'required|string|max:100',
59	            'description' => 'nullable|string|max:2000',
60	            'address' => 'nullable|string|max:1000',
61	            'display_address' => 'nullable|string|max:255',
62	            'latitude' => 'required|numeric|between:-90,90',
63	            'longitude' => 'required|numeric|between:-180,180',
64	            'is_active' => 'nullable|boolean',
65	            'metadata' => 'nullable|array',
66	        ]);
67	
68	        $location = Location::create($request->only([
69	            'name', 'type', 'description', 'address', 'display_address',
70	            'latitude', 'longitude', 'is_active', 'metadata',
71	        ]));
72	
73	        return response()->json([
74	            'message' => 'Location created successfully.',
75	            'data' => $this->locationService->formatForAuthorized($location),
76	        ], 201);
77	    }
78	
79	    public function show(Request $request, int $id): JsonResponse
80	    {
81	        $location = Location::findOrFail($id);
82	
83	        $canViewPrecise = $this->canViewPreciseCoordinates($request);
84	        $data = $canViewPrecise
85	            ? $this->locationService->formatForAuthorized($location)
86	            : $this->locationService->formatForUnauthorized($location);
87	
88	        return response()->json(['data' => $data]);
