92	    {
93	        $request->validate([
94	            'name' => 'sometimes|required|string|max:255',
95	            'type' => 'sometimes|required|string|max:100',
96	            'description' => 'nullable|string|max:2000',
97	            'address' => 'nullable|string|max:1000',
98	            'display_address' => 'nullable|string|max:255',
99	            'latitude' => 'sometimes|required|numeric|between:-90,90',
100	            'longitude' => 'sometimes|required|numeric|between:-180,180',
101	            'is_active' => 'nullable|boolean',
102	            'metadata' => 'nullable|array',
103	        ]);
104	
105	        $location = Location::findOrFail($id);
106	        $location->update($request->only([
107	            'name', 'type', 'description', 'address', 'display_address',
