122	        return response()->json(['message' => 'Location deleted successfully.']);
123	    }
124	
125	    /**
126	     * Find nearby locations within geofence radius, sorted by distance.
127	     */
128	    public function nearby(Request $request): JsonResponse
129	    {
130	        $request->validate([
131	            'latitude' => 'required|numeric|between:-90,90',
132	            'longitude' => 'required|numeric|between:-180,180',
133	            'radius_km' => 'nullable|numeric|min:0.1|max:500',
134	        ]);
135	
136	        $nearby = $this->locationService->findNearby(
137	            (float) $request->latitude,
138	            (float) $request->longitude,
139	            $request->has('radius_km') ? (float) $request->radius_km : null
140	        );
141	
142	        $canViewPrecise = $this->canViewPreciseCoordinates($request);
143	
144	        $formatted = $nearby->map(function (Location $location) use ($canViewPrecise) {
145	            $distanceKm = $location->getAttribute('distance_km');
146	            return $canViewPrecise
147	                ? $this->locationService->formatForAuthorized($location, $distanceKm)
148	                : $this->locationService->formatForUnauthorized($location, $distanceKm);
149	        })->values();
150	
151	        return response()->json([
152	            'data' => $formatted,
153	            'count' => $formatted->count(),
154	        ]);
155	    }
156	
157	    /**
158	     * Check if a point is within a location's geofence.
159	     */
160	    public function geofenceCheck(Request $request, int $id): JsonResponse
161	    {
162	        $request->validate([
163	            'latitude' => 'required|numeric|between:-90,90',
164	            'longitude' => 'required|numeric|between:-180,180',
165	            'radius_km' => 'nullable|numeric|min:0.1|max:500',
166	        ]);
167	
168	        $location = Location::findOrFail($id);
169	
170	        $isWithin = $this->locationService->isWithinGeofence(
171	            (float) $request->latitude,
172	            (float) $request->longitude,
173	            $location,
174	            $request->has('radius_km') ? (float) $request->radius_km : null
175	        );
176	
177	        $distance = $this->locationService->haversineDistance(
178	            (float) $request->latitude,
179	            (float) $request->longitude,
180	            $location->latitude,
181	            $location->longitude
182	        );
183	
184	        $response = [
185	            'location_id' => $location->id,
186	            'within_geofence' => $isWithin,
187	        ];
188	
189	        // Only expose exact distance to users with precise-coordinate permission
190	        if ($this->canViewPreciseCoordinates($request)) {
191	            $response['distance_km'] = round($distance, 3);
192	        }
193	
194	        return response()->json($response);
195	    }
196	
197	    /**
198	     * Determine if the current user can view precise coordinates.
199	     */
200	    private function canViewPreciseCoordinates(Request $request): bool
201	    {
202	        $user = $request->user();
203	
204	        if (!$user) {
205	            return false;
206	        }
207	
208	        return $user->hasPermission('locations.view_precise');
209	    }
210	}
