    {
        $fingerprint = $this->generateIdentifierFingerprint($type, $value);

        // Check for existing identifiers with the same normalized fingerprint
        $existing = LearnerIdentifier::where('type', $type)
            ->where('fingerprint', $fingerprint)
            ->first();

