76	
77	        $approval = Approval::with('enrollment')->findOrFail($id);
78	        $enrollment = $approval->enrollment;
79	
80	        // Object-level auth: only the assigned reviewer (or admin) may decide
81	        if ($approval->reviewer_id && $approval->reviewer_id !== $request->user()->id
82	            && !$request->user()->hasRole('admin')) {
83	            return response()->json([
84	                'error' => 'Forbidden',
85	                'message' => 'You are not assigned to this approval.',
86	            ], 403);
87	        }
88	
89	        if (!$approval->isPending()) {
90	            return response()->json([
91	                'error' => 'Invalid State',
92	                'message' => 'This approval has already been decided.',
93	            ], 422);
94	        }
95	
96	        if ($enrollment->status !== Enrollment::STATUS_UNDER_REVIEW) {
97	            return response()->json([
98	                'error' => 'Invalid State',
99	                'message' => 'The enrollment is not currently in review.',
100	            ], 422);
101	        }
102	
103	        // Dispatch to queue for processing
104	        ProcessEnrollmentApproval::dispatch(
105	            $enrollment->id,
106	            $request->user()->id,
107	            $request->decision,
108	            $request->comments,
109	            $request->reason_code
110	        );
111	
112	        return response()->json([
113	            'message' => 'Approval decision queued for processing.',
114	            'approval_id' => $approval->id,
115	            'enrollment_id' => $enrollment->id,
116	            'decision' => $request->decision,
117	        ], 202);
